Here's a JavaScript function that checks for prime numbers in a given array:

```javascript
function isPrime(num) {
  if (num <= 1) {
    return false;
  }
  for (let i = 2; i < num; i++) {
    if (num % i === 0) {
      return false;
    }
  }
  return true;
}

function checkForPrimeNumbers(arr) {
  if (arr.length !== 5) {
    console.log("Input array must contain exactly 5 numbers");
    return;
  }

  for (let i = 0; i < arr.length; i++) {
    if (isPrime(arr[i])) {
      console.log(arr[i]);
    }
  }
}

// Example usage:
const numbers = [2, 11, 4, 15, 29];
checkForPrimeNumbers(numbers);
```

This function first defines an `isPrime` helper function that checks if a single number is prime. The main `checkForPrimeNumbers` function then iterates through the input array, checks if each number is prime using the `isPrime` function, and prints the prime numbers to the console.

Here's a simple HTML and CSS code to create a modal with a fake chat history containing 4 messages:

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Fake Chatbot Modal</title>
<style>
  body {
    font-family: Arial, sans-serif;
  }

  .modal {
    display: none;
    position: fixed;
    z-index: 1;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    overflow: auto;
    background-color: rgba(0, 0, 0, 0.5);
  }

  .modal-content {
    background-color: #f1f1f1;
    margin: 15% auto;
    padding: 20px;
    border: 1px solid #888;
    width: 80%;
  }

  .close {
    color: #aaa;
    float: right;
    font-size: 28px;
    font-weight: bold;
  }

  .close:hover,
  .close:focus {
    color: black;
    text-decoration: none;
    cursor: pointer;
  }

  .message {
    padding: 10px;
    margin-bottom: 10px;
    border-radius: 5px;
  }

  .message.bot {
    background-color: #e6e6e6;
    text-align: left;
  }

  .message.user {
    background-color: #4CAF50;
    color: white;
    text-align: right;
  }
</style>
</head>
<body>

<h2>Fake Chatbot Modal</h2>

<!-- Trigger the modal with a button -->
<button id="myBtn">Open Modal</button>

<!-- The Modal -->
<div id="myModal" class="modal">
  <!-- Modal content -->
  <div class="modal-content">
    <span class="close">&times;</span>
    <div class="message bot">Hello! I'm your chatbot.</div>
    <div class="message user">Hi, chatbot!</div>
    <div class="message bot">How can I help you today?</div>
    <div class="message user">Tell me a joke, please.</div>
  </div>
</div>

<script>
// Get the modal
var modal = document.getElementById("myModal");

// Get the button that opens the modal
var btn = document.getElementById("myBtn");

// Get the <span> element that closes the modal
var span = document.getElementsByClassName("close")[0];

// When the user clicks the button, open the modal 
btn.onclick = function() {
  modal.style.display = "block";
}

// When the user clicks on <span> (x), close the modal
span.onclick = function() {
  modal.style.display = "none";
}

// When the user clicks anywhere outside of the modal, close it
window.onclick = function(event) {
  if (event.target == modal) {
    modal.style.display = "none";
  }
}
</script>

</body>
</html>
```

This code will create a modal with a fake chat history containing 2 messages from the bot and 2 messages from the human user. The modal can be opened by clicking on the "Open Modal" button.

